+void WiimoteNode::set_led_bit(uint8_t led, bool on)
+{
+  uint8_t bit;
+
+  if (led > 3) {
+    RCLCPP_WARN(logger_, "LED ID %d out of bounds; ignoring!", led);
+  }
+
+  bit = 1 << led;
+
+  if (on) {  // Set bit
+    led_state_ |= bit;
+  } else {  // Clear bit
+    led_state_ &= ~(bit);
+  }
+}
+void WiimoteNode::set_rumble_bit(bool on)
+{
+  if (on) {  // Set bit
+    rumble_ |= 0x1;
+  } else {  // Clear bit
+    rumble_ &= ~(0x1);
+  }
+}
